11	const COMPONENT_TYPES = ["rune"];
12	const COMPONENT_PREMIUM = 25;
13	const BLOCK_SIZE = 3;
14	const BLOCK_PREMIUM = 60;
15	
16	const isComponent = (item: Item): boolean =>
17	  COMPONENT_TYPES.includes(item.type);
18	
19	// Components of the same type form blocks of exactly 3, each priced at a
20	// discounted BLOCK_PREMIUM; leftover components are priced individually.
21	const componentBasePremium = (count: number): number => {
22	  const blocks = Math.floor(count / BLOCK_SIZE);
23	  const leftover = count % BLOCK_SIZE;
24	  return blocks * BLOCK_PREMIUM + leftover * COMPONENT_PREMIUM;
25	};
