35	// Premiums are rounded UP, in MHPCO's favor. The toFixed(6) collapses
36	// floating-point artifacts (e.g. 197.49999999) so we don't round a value
37	// that is only spuriously above a whole number.
38	const roundUpInMHPCOsFavor = (amount: number): number =>
39	  Math.ceil(Number(amount.toFixed(6)));
40	
41	const basePremiumForItem = (item: Item): number =>
42	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
