44	export const quote = (
45	  customer: unknown,
46	  step: QuoteStep,
47	  quoteIndex: number,
48	): number => {
49	  const mainItems = step.items.filter((item) => !isComponent(item));
50	  const components = step.items.filter(isComponent);
51	
52	  const mainBase = mainItems.reduce(
53	    (sum, item) => sum + basePremiumForItem(item),
54	    0,
55	  );
56	
57	  const componentCounts = new Map<string, number>();
58	  for (const component of components) {
59	    componentCounts.set(
60	      component.type,
61	      (componentCounts.get(component.type) ?? 0) + 1,
62	    );
63	  }
64	  let componentBase = 0;
65	  for (const count of componentCounts.values()) {
66	    componentBase += componentBasePremium(count);
67	  }
68	
69	  const policyBasePremium = mainBase + componentBase;
70	  const withFirstInsurance = policyBasePremium * (1 + FIRST_INSURANCE_SURCHARGE);
71	  const total = withFirstInsurance + PROCESSING_FEE;
72	  return roundUpInMHPCOsFavor(total);
73	};
